4	/** Chalk instance with forced color (level 1 = basic ANSI) for --list output */
5	const colorChalk = new Chalk({ level: 1 });
6	
7	const UUID_REGEX =
8	  /([0-9a-f]{8}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{4}-[0-9a-f]{12})/i;
9	const HEX8_TRAIL_REGEX = /([0-9a-f]{8})$/i;
10	
11	/**
12	 * 從 session 檔案路徑提取完整 session ID。
13	 * - Claude / Cursor: `{UUID}.jsonl` → UUID
14	 * - Codex: `rollout-{ts}-{UUID}.jsonl` → UUID
15	 * - Gemini: `session-{ts}-{hex8}.json` → hex8
16	 * - Fallback: basename 去副檔名
17	 */
18	export function extractFullId(path: string): string {
19	  const basename = path.split('/').pop() ?? '';
20	  const stem = basename.replace(/\.(jsonl|json|pb)$/i, '');
21	  const uuidMatch = UUID_REGEX.exec(stem);
22	  if (uuidMatch) return uuidMatch[1]!;
23	  const hex8Match = HEX8_TRAIL_REGEX.exec(stem);
24	  if (hex8Match) return hex8Match[1]!;
25	  return stem;
26	}
27	
28	/**
29	 * Format a Date as relative time string (e.g., "3m ago", "1h ago")
30	 */
31	export function formatRelativeTime(date: Date): string {
32	  const diffMs = Date.now() - date.getTime();
33	  if (diffMs < 1000) return 'just now';
34	
35	  const diffSec = Math.floor(diffMs / 1000);
36	  if (diffSec < 60) return `${diffSec}s ago`;
37	
38	  const diffMin = Math.floor(diffSec / 60);
39	  if (diffMin < 60) return `${diffMin}m ago`;
40	
41	  const diffHour = Math.floor(diffMin / 60);
42	  if (diffHour < 24) return `${diffHour}h ago`;
43	
44	  const diffDay = Math.floor(diffHour / 24);
45	  return `${diffDay}d ago`;
46	}
47	
48	const AGENT_COLORS: Record<AgentType, (s: string) => string> = {
49	  claude: (s) => colorChalk.magenta(s),
50	  codex: (s) => colorChalk.green(s),
51	  gemini: (s) => colorChalk.blue(s),
52	  cursor: (s) => colorChalk.yellow(s),
53	  agy: (s) => colorChalk.cyan(s),
54	};
55	
56	/**
57	 * Format a list of sessions as tab-separated lines
58	 */
59	export function formatSessionList(
60	  items: SessionListItem[],
61	  options: { color: boolean }
62	): string[] {
63	  return items.map((item) => {
64	    const agentStr = options.color
65	      ? AGENT_COLORS[item.agentType](item.agentType)
66	      : item.agentType;
67	
68	    const columns = [
69	      item.shortId,
70	      extractFullId(item.path),
71	      formatRelativeTime(item.lastActivityTime ?? item.mtime),
72	      agentStr,
73	      item.project ?? '',
74	      item.customTitle ? `"${item.customTitle}"` : '',
75	    ];
76	
77	    return columns.join('\t');
78	  });
79	}
