const path = '/Users/pc035860/code/agent-tail/src/index.ts';
let src = await Bun.file(path).text();

// Each stdin block:
//   - starts with a comment line containing "設定鍵盤監聽" or "Keyboard Handling"
//   - opens an `if (process.stdin.isTTY) {` block with setRawMode + on('data', ...)
//   - closes with a matching `}` followed by a blank line
//
// We replace each block (comment + if-block) with a single helper call.

const blockPattern =
  /\n  (?:\/\/ 設定鍵盤監聽[^\n]*|\/\/ ={5,} Keyboard Handling ={5,})\n  if \(process\.stdin\.isTTY\) \{\n(?:.*\n)*?  \}\n/g;

let count = 0;
src = src.replace(blockPattern, () => {
  count++;
  return '\n  // Keyboard listener (cleanup is declared later — wrap in thunk so TDZ resolves at key press time, not install time)\n  installInteractiveKeyboard(sessionManager, () => cleanup());\n';
});

console.log(`Replaced ${count} blocks`);
await Bun.write(path, src);
