1	import { homedir } from 'node:os';
2	import { join } from 'node:path';
3	
4	// SPEC §3.1 file layout:
5	//   ~/.claude/projects/{enc-cwd}/{session-uuid}/
6	//     ├── workflows/{wf_*}.json                         ← snapshot
7	//     └── subagents/workflows/{wf_*}/journal.jsonl      ← event stream
8	//                                  /agent-{17hex}.jsonl ← per-subagent transcript
9	//
10	// Path helpers stay pure — no I/O, no ID validation. Callers validate IDs via
11	// the isValid* helpers below before consuming results from filesystem scans.
12	
13	const WORKFLOW_RUN_ID_REGEX = /^wf_[0-9a-f]{8}-[0-9a-f]{3}$/;
14	const WORKFLOW_AGENT_ID_REGEX = /^[0-9a-f]{17}$/;
15	const WORKFLOW_SNAPSHOT_FILENAME_REGEX = /^(wf_[0-9a-f]{8}-[0-9a-f]{3})\.json$/;
16	const WORKFLOW_AGENT_FILENAME_REGEX = /^agent-([0-9a-f]{17})\.jsonl$/;
17	
18	export function getClaudeProjectsRoot(): string {
19	  return join(homedir(), '.claude', 'projects');
20	}
21	
22	export function getWorkflowsDir(sessionDir: string): string {
23	  return join(sessionDir, 'workflows');
24	}
25	
26	export function getWorkflowSubagentsDir(sessionDir: string): string {
27	  return join(sessionDir, 'subagents', 'workflows');
28	}
29	
30	export function getWorkflowRunDir(sessionDir: string, runId: string): string {
31	  return join(getWorkflowSubagentsDir(sessionDir), runId);
32	}
33	
34	export function getWorkflowSnapshotPath(
35	  sessionDir: string,
36	  runId: string
37	): string {
38	  return join(getWorkflowsDir(sessionDir), `${runId}.json`);
39	}
40	
41	export function getWorkflowJournalPath(
42	  sessionDir: string,
43	  runId: string
44	): string {
45	  return join(getWorkflowRunDir(sessionDir, runId), 'journal.jsonl');
46	}
47	
48	export function getWorkflowAgentPath(
49	  sessionDir: string,
50	  runId: string,
51	  agentId: string
52	): string {
53	  return join(getWorkflowRunDir(sessionDir, runId), `agent-${agentId}.jsonl`);
54	}
55	
56	// SPEC §11.2 R4-B1 — `/Users/x/code/foo` → `-Users-x-code-foo`.
57	// Sole runtime caller is the P3 dispatcher handling `--workflow` without
58	// runId; converts cwd into a fuzzy filter that matches Claude project dir
59	// names via `path.includes(filter)`.
60	export function cwdToClaudeProjectFilter(cwd: string): string {
61	  return cwd.replaceAll('/', '-');
62	}
63	
64	export function isValidWorkflowRunId(s: string): boolean {
65	  return WORKFLOW_RUN_ID_REGEX.test(s);
66	}
67	
68	export function isValidWorkflowAgentId(s: string): boolean {
69	  return WORKFLOW_AGENT_ID_REGEX.test(s);
70	}
71	
