1	import type { WatchedFile } from './multi-file-watcher.ts';
2	
3	/**
4	 * Watcher session 資訊
5	 */
6	export interface WatcherSession {
7	  id: string; // 識別碼（如 "main" 或 agentId）
8	  label: string; // 顯示標籤（如 "[MAIN]" 或 "[a0627b6]"）
9	  path: string; // 檔案路徑
10	  buffer: string[]; // 輸出緩衝
11	  isDone: boolean; // 是否已結束
12	  createdAt: number; // 建立時間戳記（毫秒）
13	  displayName?: string; // 自訂顯示名稱（優先於 label），如 Claude custom-title
14	}
15	
16	/**
17	 * SessionManager 選項
18	 */
19	export interface SessionManagerOptions {
20	  /** 每個 session 的緩衝大小限制（行數），預設 1000 */
21	  bufferSize?: number;
22	  /** active session 的輸出回調 */
23	  onOutput: (content: string, session: WatcherSession) => void;
24	  /** 新 session 加入時的回調 */
25	  onSessionAdded?: (session: WatcherSession) => void;
26	  /** session 切換時的回調 */
27	  onSessionSwitched?: (
28	    session: WatcherSession,
29	    allSessions: WatcherSession[]
30	  ) => void;
31	}
32	
33	/**
34	 * Session 管理器 - 管理多個 watcher session 的輸出切換
35	 *
36	 * 用於 interactive mode，讓使用者可以在主會話和 subagent 之間切換顯示。
37	 * 專注於 session 狀態管理和輸出路由，不直接控制 file watching。
38	 */
39	export class SessionManager {
40	  private sessions: WatcherSession[] = [];
41	  private activeIndex: number = 0;
42	  private bufferSize: number;
43	  private options: SessionManagerOptions;
44	
45	  constructor(options: SessionManagerOptions) {
46	    this.options = options;
47	    this.bufferSize = options.bufferSize ?? 1000;
48	  }
49	
50	  /**
51	   * 新增 session
52	   * - main session 永遠在 index 0
53	   * - 其他 session 插入到 index 1（新的在左邊）
54	   */
55	  addSession(
56	    id: string,
57	    label: string,
58	    path: string,
59	    displayName?: string
60	  ): WatcherSession {
61	    // 檢查是否已存在
62	    const existing = this.sessions.find((s) => s.id === id);
63	    if (existing) {
64	      return existing;
65	    }
66	
67	    const session: WatcherSession = {
68	      id,
69	      label,
70	      path,
71	      buffer: [],
72	      isDone: false,
73	      createdAt: Date.now(),
74	      displayName,
75	    };
76	
77	    // 排序邏輯：
78	    // - main session 永遠在 index 0
79	    // - 其他 session 插入到 index 1（新的在左邊）
80	    if (id === 'main') {
81	      this.sessions.unshift(session); // main 放在最前面
82	      // 插入到 0，所有元素往後移，activeIndex 要 +1
83	      // 但如果是第一次新增 session，保持 activeIndex = 0
84	      if (this.sessions.length > 1) {
85	        this.activeIndex++;
86	      }
87	    } else {
88	      // 找到 main session 的位置，插入其後
89	      const insertIndex = this.sessions[0]?.id === 'main' ? 1 : 0;
90	      this.sessions.splice(insertIndex, 0, session);
91	      // 如果插入位置 <= activeIndex，activeIndex 要 +1 以保持使用者看到相同的 session
92	      if (insertIndex <= this.activeIndex) {
93	        this.activeIndex++;
94	      }
95	    }
96	
97	    this.options.onSessionAdded?.(session);
98	
99	    return session;
100	  }
101	
102	  /**
103	   * 取得所有 sessions
104	   */
105	  getAllSessions(): WatcherSession[] {
106	    return [...this.sessions];
107	  }
108	
109	  /**
110	   * 取得目前 active 的 session
111	   */
112	  getActiveSession(): WatcherSession | null {
113	    return this.sessions[this.activeIndex] ?? null;
114	  }
115	
116	  /**
117	   * 取得 active index
118	   */
119	  getActiveIndex(): number {
120	    return this.activeIndex;
121	  }
122	
123	  /**
124	   * 切換到下一個 session
125	   */
126	  switchNext(): WatcherSession | null {
127	    if (this.sessions.length === 0) return null;
128	
129	    this.activeIndex = (this.activeIndex + 1) % this.sessions.length;
130	    const session = this.sessions[this.activeIndex] ?? null;
131	    if (session) {
132	      this.options.onSessionSwitched?.(session, this.sessions);
133	    }
134	
135	    return session;
136	  }
137	
138	  /**
139	   * 切換到上一個 session
140	   */
141	  switchPrev(): WatcherSession | null {
142	    if (this.sessions.length === 0) return null;
143	
144	    this.activeIndex =
145	      (this.activeIndex - 1 + this.sessions.length) % this.sessions.length;
146	    const session = this.sessions[this.activeIndex] ?? null;
147	    if (session) {
148	      this.options.onSessionSwitched?.(session, this.sessions);
149	    }
150	
151	    return session;
152	  }
153	
154	  /**
155	   * 切換到指定 session（by id）
156	   */
157	  switchTo(id: string): WatcherSession | null {
158	    const index = this.sessions.findIndex((s) => s.id === id);
159	    if (index === -1) return null;
160	
161	    this.activeIndex = index;
162	    const session = this.sessions[this.activeIndex] ?? null;
163	    if (session) {
164	      this.options.onSessionSwitched?.(session, this.sessions);
165	    }
166	
167	    return session;
168	  }
169	
170	  /**
171	   * 處理輸出
172	   * - active session: 直接輸出，同時存入 buffer（供切換後回看）
173	   * - 非 active session: 存入 buffer
174	   */
175	  handleOutput(label: string, content: string): void {
176	    const session = this.sessions.find((s) => s.label === label);
177	    if (!session) return;
178	
179	    const activeSession = this.getActiveSession();
180	
181	    // 所有 session 都存入 buffer（全量緩衝）
182	    session.buffer.push(content);
183	
184	    // 限制 buffer 大小
185	    if (session.buffer.length > this.bufferSize) {
186	      session.buffer.shift();
187	    }
188	
189	    // Active session 同時輸出到顯示
190	    if (session === activeSession) {
191	      this.options.onOutput(content, session);
192	    }
193	  }
194	
195	  /**
196	   * 取得 session 的緩衝內容（回傳 copy 以防止外部意外修改）
197	   */
198	  getSessionBuffer(id: string): string[] {
199	    const session = this.sessions.find((s) => s.id === id);
200	    return session?.buffer.slice() ?? [];
201	  }
202	
203	  /**
204	   * 清空 session 的緩衝
205	   */
206	  clearSessionBuffer(id: string): void {
207	    const session = this.sessions.find((s) => s.id === id);
208	    if (session) {
209	      session.buffer = [];
210	    }
211	  }
212	
213	  /**
214	   * 更新 session 的 displayName（例如 Claude custom-title 變更時）
215	   */
216	  updateSessionDisplayName(id: string, displayName: string): void {
217	    const session = this.sessions.find((s) => s.id === id);
218	    if (session) {
219	      session.displayName = displayName;
220	    }
221	  }
222	
223	  /**
224	   * 標記 session 為已結束
225	   */
226	  markSessionDone(id: string): void {
227	    const session = this.sessions.find((s) => s.id === id);
228	    if (session) {
229	      session.isDone = true;
230	    }
231	  }
232	
233	  /**
234	   * 輸出當前 active session 的緩衝內容（切換後顯示歷史）
235	   */
236	  flushActiveBuffer(): void {
237	    const session = this.getActiveSession();
238	    if (!session || session.buffer.length === 0) return;
239	
240	    for (const content of session.buffer) {
241	      this.options.onOutput(content, session);
242	    }
243	
244	    session.buffer = [];
245	  }
246	
247	  /**
248	   * 建立 WatchedFile 列表給 MultiFileWatcher 使用
249	   */
250	  getWatchedFiles(): WatchedFile[] {
251	    return this.sessions.map((s) => ({
252	      path: s.path,
253	      label: s.label,
254	    }));
255	  }
256	
257	  /**
258	   * Session 總數
259	   */
260	  get sessionCount(): number {
261	    return this.sessions.length;
262	  }
