1	import { watch, type FSWatcher } from 'node:fs';
2	import { stat } from 'node:fs/promises';
3	import { join } from 'node:path';
4	import { Glob } from 'bun';
5	import { FileWatcher } from '../core/file-watcher.ts';
6	import type {
7	  OutputHandler,
8	  SessionHandler,
9	} from '../core/detector-interfaces.ts';
10	import type { Formatter } from '../formatters/formatter.interface.ts';
11	import { ClaudeAgent } from '../agents/claude/claude-agent.ts';
12	import type { LineParser } from '../agents/agent.interface.ts';
13	import { drainParser } from '../utils/parser-drain.ts';
14	import chalk from 'chalk';
15	import { JournalLineParser } from './journal-parser.ts';
16	import { SnapshotWatcher } from './snapshot-watcher.ts';
17	import {
18	  parseWorkflowAgentFilename,
19	  isValidWorkflowAgentId,
20	  makeWorkflowJournalSessionId,
21	} from './paths.ts';
22	import type {
23	  DetectedWorkflow,
24	  WorkflowProgressItem,
25	  WorkflowSnapshot,
26	} from './types.ts';
27	
28	// SPEC §10.2 — WorkflowAttachment manages the lifecycle of a single
29	// workflow run's watchers (journal + agent transcripts + subagent dir).
30	
31	const TRANSCRIPT_DIR_RETRIES = 10;
32	const TRANSCRIPT_DIR_INTERVAL_MS = 100;
33	
34	export interface WorkflowAttachmentConfig {
35	  workflow: DetectedWorkflow;
36	  withAgents: boolean;
37	  verbose: boolean;
38	  follow: boolean;
39	  pollInterval?: number;
40	  initialLines?: number;
41	  formatter: Formatter;
42	  /** Per-line output. label is `[wf:{runId}:journal]` or `[wf:{shortAgentId}]`. */
43	  onOutput: (formatted: string, label: string) => void;
44	  outputHandler: OutputHandler;
45	  sessionHandler?: SessionHandler;
46	  /** P5 — called at the end of stop() so dispatcher can drop refs / unregister. */
47	  onStop?: (reason: 'completed' | 'directory-removed' | 'user') => void;
48	}
49	
50	export function makeWorkflowJournalLabel(runId: string): string {
51	  return `[wf:${runId}:journal]`;
52	}
53	
54	export function makeWorkflowAgentLabel(agentId: string): string {
55	  return `[wf:${agentId.slice(0, 7)}]`;
56	}
57	
58	export class WorkflowAttachment {
59	  private journalWatcher: FileWatcher | null = null;
60	  private journalParser: JournalLineParser | null = null;
61	  private readonly agentWatchers = new Map<string, FileWatcher>();
62	  private readonly agentParsers = new Map<string, LineParser>();
63	  private subagentDirWatcher: FSWatcher | null = null;
64	  private snapshotWatcher: SnapshotWatcher | null = null;
65	  private currentSnapshot: WorkflowSnapshot | null = null;
66	  // One-shot latch — true once auto-exit (snapshot terminal status) is
67	  // scheduled, so duplicate terminal-status snapshots don't schedule
68	  // multiple stop() calls.
69	  private autoStopScheduled = false;
70	  private readonly knownAgentIds = new Set<string>();
71	  private stopped = false;
72	
73	  constructor(private readonly config: WorkflowAttachmentConfig) {}
74	
75	  getCurrentSnapshot(): WorkflowSnapshot | null {
76	    return this.currentSnapshot;
77	  }
78	
79	  async start(): Promise<void> {
80	    await this._waitForTranscriptDir();
81	
82	    // Step 1 — journal
83	    await this._startJournalAndFlushHistory();
84	
85	    // Step 2/3 — workflow agents (initial scan + directory watch)
86	    if (this.config.withAgents) {
87	      await this._scanAndAttachInitialAgents();
88	      this._startSubagentDirWatch();
89	    }
90	
91	    // Step 4 — snapshot watcher (LAST, so onChange-triggered stop runs after
92	    // history dump completes — see _startJournalAndFlushHistory note).
93	    this.snapshotWatcher = new SnapshotWatcher({
94	      path: this.config.workflow.snapshotPath,
95	      onChange: (snap) => this._handleSnapshotChange(snap),
96	      onError: (err) => this._handleSnapshotError(err),
97	    });
98	    await this.snapshotWatcher.start();
99	  }
100	
101	  async attachAgent(agentId: string, transcriptPath: string): Promise<void> {
102	    // Post-stop subagent-dir-watch events must not spawn new watchers
103	    // during the queueMicrotask gap between scheduling and executing stop().
104	    if (this.stopped) return;
105	    if (this.knownAgentIds.has(agentId)) return;
106	    this.knownAgentIds.add(agentId);
107	
108	    let succeeded = false;
109	    try {
110	      const parser = new ClaudeAgent({ verbose: this.config.verbose }).parser;
111	      this.agentParsers.set(agentId, parser);
112	
113	      const watcher = new FileWatcher();
114	      const label = makeWorkflowAgentLabel(agentId);
115	      await watcher.start(transcriptPath, {
116	        follow: this.config.follow,
117	        pollInterval: this.config.pollInterval,
118	        initialLines: this.config.initialLines,
119	        onLine: (line) => this._handleAgentLine(agentId, line, label),
120	        onError: (err) =>
121	          this.config.outputHandler.debug(
122	            `[wf:${this.config.workflow.runId}] agent ${agentId.slice(0, 7)} read error: ${err}`
123	          ),
124	      });
125	      this.agentWatchers.set(agentId, watcher);
126	
127	      this.config.sessionHandler?.addSession?.(agentId, label, transcriptPath);
128	      this.config.sessionHandler?.updateUI?.();
129	      succeeded = true;
130	    } finally {
131	      if (!succeeded) {
132	        this.knownAgentIds.delete(agentId);
133	        this.agentParsers.delete(agentId);
134	        this.agentWatchers.delete(agentId);
135	        this.config.outputHandler.debug(
136	          `[wf:${this.config.workflow.runId}] attachAgent ${agentId.slice(0, 7)} failed; rolled back`
137	        );
138	      }
139	    }
140	  }
141	
142	  async stop(
143	    reason: 'completed' | 'directory-removed' | 'user'
144	  ): Promise<void> {
145	    if (this.stopped) return;
146	    this.stopped = true;
147	
148	    // Close snapshot watcher first to silence further onChange firings.
149	    this.snapshotWatcher?.stop();
150	    this.snapshotWatcher = null;
151	
152	    this.subagentDirWatcher?.close();
153	    this.subagentDirWatcher = null;
154	
155	    this.journalWatcher?.stop();
156	    this.journalWatcher = null;
157	
158	    for (const w of this.agentWatchers.values()) {
159	      w.stop();
160	    }
161	    this.agentWatchers.clear();
162	
163	    for (const agentId of this.knownAgentIds) {
164	      this.config.sessionHandler?.markSessionDone?.(agentId);
165	    }
166	    // Journal session id matches the dispatcher's session id
167	    // (P6 interactive) and the PaneManager pinned key (P7 --workflow-pane).
168	    this.config.sessionHandler?.markSessionDone?.(
169	      makeWorkflowJournalSessionId(this.config.workflow.runId)
170	    );
171	
172	    this.config.outputHandler.info(
173	      `[wf:${this.config.workflow.runId}] stopped (${reason})`
174	    );
175	
176	    // P5 — notify owner so it can drop the runId from its registry.
177	    this.config.onStop?.(reason);
178	  }
179	
180	  // --- internals ---
181	
182	  /**
183	   * Wait for transcriptDir to exist. Uses stat() because
184	   * Bun.file(dir).exists() returns false for directories.
185	   */
186	  private async _waitForTranscriptDir(): Promise<void> {
187	    for (let i = 0; i < TRANSCRIPT_DIR_RETRIES; i++) {
188	      if (this.stopped) return;
189	      try {
190	        await stat(this.config.workflow.transcriptDir);
191	        return;
192	      } catch {
193	        await new Promise((r) => setTimeout(r, TRANSCRIPT_DIR_INTERVAL_MS));
194	      }
195	    }
196	  }
197	
198	  private async _startJournalAndFlushHistory(): Promise<void> {
199	    const journalPath = join(
200	      this.config.workflow.transcriptDir,
201	      'journal.jsonl'
202	    );
203	
204	    let fileMtime: Date | undefined;
205	    try {
206	      fileMtime = (await stat(journalPath)).mtime;
207	    } catch {
208	      /* journal may not exist yet */
209	    }
210	
211	    this.journalParser = new JournalLineParser({ fileMtime });
212	    const label = makeWorkflowJournalLabel(this.config.workflow.runId);
213	
214	    const watcher = new FileWatcher();
215	    this.journalWatcher = watcher;
216	    await watcher.start(journalPath, {
217	      follow: this.config.follow,
218	      pollInterval: this.config.pollInterval,
219	      initialLines: this.config.initialLines,
220	      onLine: (line) => this._handleJournalLine(line, label),
221	      onError: (err) =>
222	        this.config.outputHandler.debug(
223	          `[wf:${this.config.workflow.runId}] journal read error: ${err}`
224	        ),
225	    });
226	
227	    // FileWatcher.start() awaits initial readAndProcess (see
228	    // src/core/file-watcher.ts:49) — all history lines have been emitted
229	    // to onLine. Safe to switch to live mode before the tail begins.
230	    // P4 SnapshotWatcher must start AFTER this point so its onChange
231	    // can't fire before history dump completes.
232	    this.journalParser.markLiveMode();
233	  }
234	
235	  private _handleJournalLine(line: string, label: string): void {
236	    if (!this.journalParser) return;
237	    const parsed = this.journalParser.parse(line);
238	    if (!parsed) return;
239	    parsed.sourceLabel = label;
240	    const formatted = this.config.formatter.format(parsed);
241	    if (formatted) this.config.onOutput(formatted, label);
242	  }
243	
244	  private _handleAgentLine(agentId: string, line: string, label: string): void {
245	    const parser = this.agentParsers.get(agentId);
246	    if (!parser) return;
247	    drainParser(parser, line, (parsed) => {
248	      parsed.sourceLabel = label;
249	      const formatted = this.config.formatter.format(parsed);
250	      if (formatted) this.config.onOutput(formatted, label);
251	    });
252	  }
253	
254	  private async _scanAndAttachInitialAgents(): Promise<void> {
255	    const glob = new Glob('agent-*.jsonl');
256	    const found: { agentId: string; path: string; birthtime: Date }[] = [];
257	    for await (const file of glob.scan({
258	      cwd: this.config.workflow.transcriptDir,
259	    })) {
260	      if (file.includes('/')) continue; // defensive
261	      const agentId = parseWorkflowAgentFilename(file);
262	      if (!agentId) continue;
263	      const path = join(this.config.workflow.transcriptDir, file);
264	      try {
